fn selected_agent_backend_command(message: &str) -> Option<&str> {
    let command = message.trim();
    let after_slash = command.strip_prefix('/')?;
    if after_slash
        .chars()
        .next()
        .is_some_and(|ch| !ch.is_whitespace())
    {
        Some(command)
    } else {
        None
    }
}

