pub fn record_launch_reply(
    &mut self,
    request: AgentLaunch,
    reply: String,
) -> Result<AgentSession, AgentError> {
    let mut session = AgentSession::new(request);
    session.push_message(MessageRole::Agent, reply);
    self.state
        .lock()
        .expect("codex backend state mutex poisoned")
        .sessions
        .insert(session.id.clone(), session.clone());
    Ok(session)
}

pub fn record_launch_output(
    &mut self,
    request: AgentLaunch,
    output: String,
) -> Result<AgentSession, AgentError> {
    let parsed = parse_codex_output(&output);
    if let Some(thread_id) = parsed.thread_id {
        self.state
            .lock()
            .expect("codex backend state mutex poisoned")
            .thread_ids
            .insert(request.id.clone(), thread_id);
    }
    self.record_launch_reply(request, parsed.agent_reply.unwrap_or(output))
}

pub fn session(&self, agent_id: &AgentId) -> Option<AgentSession> {
    self.state
        .lock()
        .expect("codex backend state mutex poisoned")
        .sessions
        .get(agent_id)
        .cloned()
}

fn command_output(&self, agent_id: &AgentId, command: &str) -> Result<String, AgentError> {
    let Some(command_name) = codex_backend_command_name(command) else {
        return Ok(format!(
            "backend command `{}` is not supported",
            command.trim()
        ));
    };
    match command_name {
        "status" => self.status_command_output(agent_id),
        "fork" => self.fork_command_output(agent_id),
        other => Ok(format!("Codex backend command `/{other}` is not supported")),
    }
}

fn status_command_output(&self, agent_id: &AgentId) -> Result<String, AgentError> {
    let info = self.command_session_info(agent_id)?;
    let thread = info.thread_id.as_deref().unwrap_or("unknown");
    let state = if info.active { "working" } else { "ready" };
    Ok(format!(
        "Codex status for {agent_id}\nthread: {thread}\nstate: {state}\nfeature: {}",
        info.feature
    ))
}

fn fork_command_output(&self, agent_id: &AgentId) -> Result<String, AgentError> {
    let info = self.command_session_info(agent_id)?;
    let thread = info.thread_id.as_deref().unwrap_or("unknown");
    Ok(format!(
        "Codex fork for {agent_id}\nsource thread: {thread}\nRun `codex fork {thread}` in a terminal to open an interactive fork."
    ))
}

